<script>
export default {
  data() {
    return {
      currentSteps: 0,
      positions: [],
      nextId: 1,
      isHomed: false,
      isMoving: false,
      isHoming: false,
      isProgramRunning: false,
      isProgramPaused: false,
      // isArmed: true = Arduino is in ARMED state waiting for robot signal.
      // Only the START button is disabled by isArmed.
