      showHomeDialog: false,
      showGoToPosDialog: false,
      selectedGoToPositionId: null,
      weldedPieces: 0,
      cobotTimeoutSetting: 900,
      cobotSecondsLeft: null,
      isWaitingCobot: false,
      cobotTimeoutOptions: [
        { label: "5 min", value: 300 },
        { label: "15 min", value: 900 },
        { label: "30 min", value: 1800 },
        { label: "60 min", value: 3600 },
        { label: "none", value: 0 }
      ]
    }
  },

  computed: {
    canGoToPos() {
      return this.isHomed &&
             this.positions.length > 0 &&
             !this.isArmed &&
             !this.isMoving &&
             !this.isHoming &&
             (!this.isProgramRunning || this.isProgramPaused);
    },

    goToPositionItems() {
      return [
        { id: null, label: "---------", steps: null },
        ...this.positions.map((pos, index) => ({
          id: pos.id,
          label: "POS " + (index + 1),
          steps: pos.steps
        }))
      ];
    },

    cobotTimeoutDisplay() {
      if (this.cobotTimeoutSetting === 0) return "COBOT TIMEOUT : none";
      if (this.isWaitingCobot && this.cobotSecondsLeft !== null) {
        return "ERROR IN : " + this.cobotSecondsLeft + "s";
      }
      return "ERROR IN : " + this.cobotTimeoutSetting + "s";
    },

    cobotTimeoutChipColor() {
      if (this.cobotTimeoutSetting === 0) return "grey";
      if (this.isWaitingCobot) return "orange";
      return "primary";
    },

    statusText() {
      if (this.isProgramPaused)  return "Program Paused - Press CONTINUE to resume";
      if (this.isArmed)          return "ARMED - Waiting for Robot Start Signal...";
      if (this.isProgramRunning) return "Program Running...";
      if (this.isHoming)         return "Homing in progress...";
      if (!this.isHomed)         return "NOT HOMED - Press HOMING button";
      if (this.isMoving)         return "Motor moving...";
      return "Ready";
    },

    statusColor() {
      if (this.isProgramPaused)  return "amber";
      if (this.isArmed)          return "purple";
      if (this.isProgramRunning) return "blue";
      if (!this.isHomed)         return "red";
      if (this.isMoving || this.isHoming) return "orange";
      return "green";
    }
